// Hyperrealistic glass orb — two-surface refraction, Fresnel, CA, specular, DoF blur
// Input 0: sharp video  |  Input 1: blurred video (DoF outside sphere)
// Uniforms: orb_params (center.xy, radius, ior), light_params (dir.xyz, spec_power), ca_param (ca, bg_scale)

uniform vec4 orb_params;   // xy = center (0-1), z = radius (height fraction), w = IOR
uniform vec4 light_params; // xyz = light direction (normalized), w = spec exponent
uniform vec4 ca_param;     // x = ca IOR offset, y = bg_scale, z = spec_mult, w = energy (warm inner glow)

out vec4 fragColor;

vec2 sphereSampleUV(vec2 uv, vec2 cen, float radius, float n, float aspect, float bgScale) {
    vec2  d    = uv - cen;
    d.x *= aspect;
    vec2  n2D  = d / radius;
    float z    = sqrt(max(0.001, 1.0 - dot(n2D, n2D)));
    vec3  N    = vec3(n2D, z);
    vec3  I    = vec3(0.0, 0.0, -1.0);

    vec3  R1     = refract(I, N, 1.0 / n);
    float t      = -2.0 * dot(N, R1);
    vec3  P1     = N + R1 * t;
    vec3  N_exit = normalize(P1);
    vec3  R2     = refract(R1, -N_exit, n);

    // TIR sentinel
    if (dot(R2, R2) < 0.001) return vec2(-9.0);

    // Exit point in UV space + scaled ray direction for wide-FOV sampling
    vec2 exitUV = cen + vec2(P1.x / aspect, P1.y) * radius;
    vec2 bgDir  = vec2(R2.x / aspect, R2.y);
    return clamp(exitUV + bgDir * radius * bgScale, 0.001, 0.999);
}

void main() {
    vec2  uv     = vUV.st;
    float aspect = uTD2DInfos[0].res.z / uTD2DInfos[0].res.w;

    vec2  cen      = orb_params.xy;
    float radius   = orb_params.z;
    float ior      = orb_params.w;
    vec3  lightDir = normalize(light_params.xyz);
    float specPow  = light_params.w;
    float ca       = ca_param.x;
    float bgScale  = ca_param.y;
    float specMult  = ca_param.z;
    float glowEnergy = ca_param.w;

    vec2  dv       = uv - cen;
    dv.x *= aspect;
    float dist     = length(dv);
    float normDist = dist / radius;

    // Outside sphere — blurred bg + contact shadow + caustic pool
    if (normDist >= 1.0) {
        vec4 blurred = texture(sTD2DInputs[1], uv);

        vec2  shadowCen  = vec2(cen.x, cen.y - radius * 1.05);
        vec2  shadowD    = (uv - shadowCen) * vec2(aspect, 2.8);
        float shadowFall = exp(-dot(shadowD, shadowD) * 55.0);

        vec2  causticCen  = shadowCen + vec2(-light_params.x, 0.0) * radius * 0.5;
        vec2  causticD    = (uv - causticCen) * vec2(aspect, 3.5);
        float causticFall = exp(-dot(causticD, causticD) * 48.0);

        float shadow = 1.0 - 0.28 * shadowFall + 0.38 * causticFall;
        fragColor = TDOutputSwizzle(vec4(blurred.rgb * shadow, blurred.a));
        return;
    }

    // Surface vectors
    vec2  n2D = dv / radius;
    float z   = sqrt(max(0.001, 1.0 - dot(n2D, n2D)));
    vec3  N   = normalize(vec3(n2D, z));
    vec3  V   = vec3(0.0, 0.0, 1.0);

    // Chromatic aberration — 3 refraction samples
    vec2 uvG = sphereSampleUV(uv, cen, radius, ior,      aspect, bgScale);
    vec2 uvR = sphereSampleUV(uv, cen, radius, ior - ca, aspect, bgScale);
    vec2 uvB = sphereSampleUV(uv, cen, radius, ior + ca, aspect, bgScale);

    // TIR — dark glassy rim (real glass sphere characteristic)
    if (uvG.x < -1.0) {
        vec4 bg = texture(sTD2DInputs[0], uv);
        float rimDark = pow(1.0 - normDist, 1.5) * 0.08;
        fragColor = TDOutputSwizzle(vec4(bg.rgb * rimDark, 1.0));
        return;
    }
    if (uvR.x < -1.0) uvR = uvG;
    if (uvB.x < -1.0) uvB = uvG;

    float r = texture(sTD2DInputs[0], uvR).r;
    float g = texture(sTD2DInputs[0], uvG).g;
    float b = texture(sTD2DInputs[0], uvB).b;

    // Boost saturation + contrast so refracted scene reads vivid through glass
    vec3 refractRGB = vec3(r, g, b);
    float lum = dot(refractRGB, vec3(0.2126, 0.7152, 0.0722));
    refractRGB = mix(vec3(lum), refractRGB, 1.5);
    refractRGB = pow(max(refractRGB, 0.0), vec3(1.2));

    // Fresnel (Schlick)
    float cosTheta = max(dot(N, V), 0.0);
    float R0       = pow((1.0 - ior) / (1.0 + ior), 2.0);
    float fresnel  = R0 + (1.0 - R0) * pow(1.0 - cosTheta, 5.0);

    float rim = pow(1.0 - cosTheta, 4.0);

    // Blinn-Phong specular
    vec3  H    = normalize(V + lightDir);
    float spec = pow(max(dot(N, H), 0.0), specPow);

    // Edge darkening
    float edgeDark = pow(1.0 - normDist * 0.30, 2.0);

    // Secondary internal reflection
    vec3  lightDir2 = normalize(lightDir * vec3(-0.5, 0.3, 1.0));
    float spec2     = pow(max(dot(N, normalize(V + lightDir2)), 0.0), specPow * 0.35) * 0.22;

    vec3 sphereRGB = refractRGB * edgeDark;
    sphereRGB += vec3(spec) * specMult;
    sphereRGB += vec3(spec2) * 1.1;

    // Warm inner glow — energy builds a soft Act 1 purple warmth at orb center
    float glowFall = exp(-normDist * normDist * 5.0);
    vec3  glowColor = vec3(0.70, 0.18, 0.95);
    sphereRGB += glowColor * glowFall * glowEnergy * 0.5;

    // Scene reflection on outer glass surface
    vec3  Rrefl   = reflect(vec3(0.0, 0.0, -1.0), N);
    vec2  reflUV  = clamp(cen + vec2(Rrefl.x / aspect, Rrefl.y) * radius, 0.001, 0.999);
    vec3  reflCol = texture(sTD2DInputs[0], reflUV).rgb;
    sphereRGB     = mix(sphereRGB, reflCol, fresnel * fresnel * 0.9);

    // Embed orb into scene
    vec4 bg       = texture(sTD2DInputs[0], uv);
    vec3 embedded = mix(bg.rgb, sphereRGB, 0.97);

    float mask = smoothstep(1.0, 0.972, normDist);
    fragColor  = TDOutputSwizzle(mix(bg, vec4(embedded, 1.0), mask));
}
